# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;

public struct ShopItem
{
    public string Name;
    public int Cost;
    public int HealthRestoreAmount;
    public int CurrencyBonus;
    public int DamageBoost;

    public ShopItem(string name, int cost, int healthRestore = 0, int currencyBonus = 0, int damageBoost = 0)
    {
        Name = name;
        Cost = cost;
        HealthRestoreAmount = healthRestore;
        CurrencyBonus = currencyBonus;
        DamageBoost = damageBoost;
    }
}

public class PlayerManager : MonoBehaviour
{
    public int currentHealth;
    public int maxHealth = 100;
    public int currentCurrency;
    public int baseDamage = 10;

    void Start()
    {
        currentHealth = maxHealth;
        currentCurrency = 500;
    }

    public void TakeDamage(int amount)
    {
        if (amount < 0) return;

        currentHealth -= amount;
        if (currentHealth < 0)
        {
            currentHealth = 0;
        }
    }

    public void Heal(int amount)
    {
        if (amount < 0) return;

        currentHealth += amount;
        if (currentHealth > maxHealth)
        {
            currentHealth = maxHealth;
        }
    }

    public bool TryPurchaseItem(ShopItem item)
    {
        if (currentCurrency >= item.Cost)
        {
            currentCurrency -= item.Cost;

            if (item.HealthRestoreAmount > 0)
            {
                Heal(item.HealthRestoreAmount);
            }
            if (item.CurrencyBonus > 0)
            {
                currentCurrency += item.CurrencyBonus;
            }
            if (item.DamageBoost > 0)
            {
                baseDamage += item.DamageBoost;
            }
            return true;
        }
        else
        {
            return false;
        }
    }

    void Update()
    {
        if (Input.GetKeyDown(KeyCode.D))
        {
            TakeDamage(15);
        }

        if (Input.GetKeyDown(KeyCode.H))
        {
            Heal(20);
        }

        if (Input.GetKeyDown(KeyCode.B))
        {
            ShopItem healthPotion = new ShopItem("Health Potion", 50, healthRestore: 30);
            TryPurchaseItem(healthPotion);
        }

        if (Input.GetKeyDown(KeyCode.M))
        {
            ShopItem goldPack = new ShopItem("Gold Pack", 100, currencyBonus: 150);
            TryPurchaseItem(goldPack);
        }

        if (Input.GetKeyDown(KeyCode.T))
        {
            ShopItem damagePotion = new ShopItem("Damage Potion", 75, damageBoost: 5);
            TryPurchaseItem(damagePotion);
        }
    }
}